#include <stdio.h>

int main() {
  char text[6] = "Hello";
  printf("First character: %c\n", text[0]);
  printf("Second character: %c\n", text[1]);
  return 0;
}
// Output:
// First character: H
// Second character: e

#include <stdio.h>
#include <string.h>

int main() {
  char text[] = "Hello";
  int length = strlen(text);
  printf("Length of string: %d\n", length);
  return 0;
}
// Output:
// Length of string: 5

#include <stdio.h>
#include <string.h>

int main() {
  char first[20] = "Hello, ";
  char second[] = "World!";
  strcat(first, second);
  printf("Combined string: %s\n", first);
  return 0;
}
// Output:
// Combined string: Hello, World!

#include <stdio.h>
#include <string.h>

int main() {
  char str1[] = "Hello";
  char str2[] = "Hello";
  char str3[] = "World";
  if (strcmp(str1, str2) == 0) {
    printf("str1 and str2 are equal\n");
  }
  if (strcmp(str1, str3) != 0) {
    printf("str1 and str3 are not equal\n");
  }
  return 0;
}
// Output:
// str1 and str2 are equal
// str1 and str3 are not equal

